import{_ as n,H as s,f as t,i as e}from"./chunks/framework.BHvCMIhP.js";const c=JSON.parse('{"title":"安全工程系列写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"../securityLearning/00-写作计划.md","filePath":"../securityLearning/00-写作计划.md","lastUpdated":1778496697000}'),l={name:"../securityLearning/00-写作计划.md"};function i(o,a,p,r,d,h){return s(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="安全工程系列写作计划" tabindex="-1">安全工程系列写作计划 <a class="header-anchor" href="#安全工程系列写作计划" aria-label="Permalink to &quot;安全工程系列写作计划&quot;">​</a></h1><blockquote><p>来源:<code>未来系列规划.md</code> 第三类「纵深主题」第三项,⭐⭐⭐。 webLearning 用 1 篇浅讲了「认证与安全」(35-认证与安全.md),networkLearning 用 4 篇讲了 TLS / PKI / WAF / 渗透入门——<strong>这个系列把所有这些零散的&quot;安全片段&quot;接上</strong>,从「攻击者视角」一路打到「工程化防御」。 <strong>看完这层,你写代码时会有&quot;被攻击的本能&quot;</strong>——SSRF / SQL 注入 / 反序列化 / npm 投毒 / Prompt 注入,不再是&quot;听过的名词&quot;,而是能拆开讲清楚利用链 + 防御链的硬通货。</p></blockquote><hr><h2 id="设计思路" tabindex="-1">设计思路 <a class="header-anchor" href="#设计思路" aria-label="Permalink to &quot;设计思路&quot;">​</a></h2><p>六层结构,从「攻击者心智」到「防御工程」:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>心智 + 威胁建模(攻击者怎么想 / CIA / 信任边界)</span></span>
<span class="line"><span>   → 密码学(原语 → 协议 → 工程陷阱)</span></span>
<span class="line"><span>   → Web 安全深入(超越 webLearning 浅讲)</span></span>
<span class="line"><span>   → 二进制 / 内存安全(栈堆漏洞 / 缓解机制)</span></span>
<span class="line"><span>   → 渗透与攻防(CTF / 红蓝紫队 / 真实流程)</span></span>
<span class="line"><span>   → 工程化防御(SDL / 供应链 / 云安全 / AI 安全)</span></span></code></pre></div><p><strong>这个系列不是 OWASP 文档翻译</strong>——OWASP 偏列表式,<strong>本系列偏&quot;工程师视角&quot;</strong>:每个漏洞都讲清楚「漏洞原因 → 利用链 → 实战示例 → 修复 → 防御深度」,看完能直接写到代码评审清单里。</p><p>不深入到 0day 挖洞或者 APT 研究层面,<strong>而是讲清楚&quot;应用工程师能看懂、需要懂的安全图景&quot;</strong>——你写 Web / 后端 / AI 应用,但上线前必须懂这些。<strong>95% 的真实漏洞都集中在这层。</strong></p><hr><h2 id="篇目-30-篇" tabindex="-1">篇目(30 篇) <a class="header-anchor" href="#篇目-30-篇" aria-label="Permalink to &quot;篇目(30 篇)&quot;">​</a></h2><h3 id="第一层-心智与威胁建模-01-03" tabindex="-1">第一层:心智与威胁建模(01-03) <a class="header-anchor" href="#第一层-心智与威胁建模-01-03" aria-label="Permalink to &quot;第一层:心智与威胁建模(01-03)&quot;">​</a></h3><ul><li>[x] 01 安全总览(攻击者视角 / CIA 三元组 / 信任边界 / 纵深防御)</li><li>[x] 02 威胁建模实战(STRIDE / DREAD / 攻击树 / 数据流图)</li><li>[x] 03 漏洞生命周期(CVE / CVSS / 0day vs Nday / 披露 vs 隐藏)</li></ul><h3 id="第二层-密码学-04-08" tabindex="-1">第二层:密码学(04-08) <a class="header-anchor" href="#第二层-密码学-04-08" aria-label="Permalink to &quot;第二层:密码学(04-08)&quot;">​</a></h3><ul><li>[x] 04 密码学心智(随机数 / 哈希 / KDF / &quot;不要自己造密码&quot;)</li><li>[x] 05 对称加密(AES / 分组模式 / AEAD / GCM 为什么强)</li><li>[x] 06 非对称加密(RSA / DH / 椭圆曲线 / 后量子初探)</li><li>[x] 07 数字签名与证书(签名 vs 加密 / X.509 / 证书透明度)</li><li>[x] 08 密码学工程陷阱(时序攻击 / 填充 oracle / 弱随机 / KMS 与 HSM)</li></ul><h3 id="第三层-web-安全深入-09-15" tabindex="-1">第三层:Web 安全深入(09-15) <a class="header-anchor" href="#第三层-web-安全深入-09-15" aria-label="Permalink to &quot;第三层:Web 安全深入(09-15)&quot;">​</a></h3><ul><li>[x] 09 OWASP Top 10 2025(现代版重排 / 风险打分 / 怎么读这份清单)</li><li>[x] 10 XSS 全攻略(反射 / 存储 / DOM / mutation / CSP / Trusted Types)</li><li>[x] 11 CSRF / SameSite / SOP / CORS(浏览器同源模型与四种绕过)</li><li>[x] 12 注入家族(SQL / NoSQL / 命令 / LDAP / 模板 / 表达式)</li><li>[x] 13 SSRF 与 XXE(内网穿透 / 云元数据 / DTD 外部实体)</li><li>[x] 14 反序列化漏洞(Java / Python / Node / PHP 全栈视角)</li><li>[x] 15 认证授权漏洞(JWT 攻击 / OAuth 流程缺陷 / 会话固定 / 权限提升)</li></ul><h3 id="第四层-二进制-内存安全-16-20" tabindex="-1">第四层:二进制 / 内存安全(16-20) <a class="header-anchor" href="#第四层-二进制-内存安全-16-20" aria-label="Permalink to &quot;第四层:二进制 / 内存安全(16-20)&quot;">​</a></h3><ul><li>[x] 16 程序在内存里长什么样(段 / 栈帧 / 调用约定 / 复习)</li><li>[x] 17 栈溢出与 ROP(经典 stack smashing / Return-Oriented Programming)</li><li>[x] 18 堆漏洞(use-after-free / double free / heap spraying)</li><li>[x] 19 内存安全缓解机制(ASLR / DEP / Canary / CFI / Shadow Stack)</li><li>[x] 20 模糊测试与内存安全语言(AFL / libFuzzer / Rust / 为什么内存安全语言&quot;赢了&quot;)</li></ul><h3 id="第五层-渗透与攻防实战-21-25" tabindex="-1">第五层:渗透与攻防实战(21-25) <a class="header-anchor" href="#第五层-渗透与攻防实战-21-25" aria-label="Permalink to &quot;第五层:渗透与攻防实战(21-25)&quot;">​</a></h3><ul><li>[x] 21 信息搜集与侦察(OSINT / 子域名 / 端口扫描 / 指纹识别)</li><li>[x] 22 Web 渗透方法论(Burp Suite 工作流 / 手工 vs 自动化)</li><li>[x] 23 内网渗透(横向移动 / 提权 / 域渗透 / C2 流量)</li><li>[x] 24 红蓝紫队(攻防演练 / 检测覆盖 / Purple Team 思维)</li><li>[x] 25 CTF 入门(Web / Pwn / Reverse / Crypto / Misc 五大类心智)</li></ul><h3 id="第六层-工程化防御-26-30" tabindex="-1">第六层:工程化防御(26-30) <a class="header-anchor" href="#第六层-工程化防御-26-30" aria-label="Permalink to &quot;第六层:工程化防御(26-30)&quot;">​</a></h3><ul><li>[x] 26 供应链安全(npm/PyPI 投毒 / SBOM / Sigstore / SLSA)</li><li>[x] 27 安全开发生命周期(SDL / 代码审计 / SAST / DAST / IAST)</li><li>[x] 28 容器与云安全(K8s 攻击面 / IAM 错配 / Secret 管理)</li><li>[x] 29 安全监控与应急响应(IDS / SIEM / 取证 / 事件复盘)</li><li>[x] 30 AI 安全(Prompt 注入 / 数据中毒 / 模型窃取 / Agent 滥用)</li></ul><hr><h2 id="与其他系列的边界" tabindex="-1">与其他系列的边界 <a class="header-anchor" href="#与其他系列的边界" aria-label="Permalink to &quot;与其他系列的边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>已有系列</th><th>本系列</th></tr></thead><tbody><tr><td>TLS / mTLS / PKI</td><td>networkLearning/18-21 ✅</td><td>不重复,只讲密码学原语和工程陷阱(05-08)</td></tr><tr><td>WAF / DDoS 防御</td><td>networkLearning/37 ✅</td><td>不重复,讲 WAF <strong>绕过</strong> 思路</td></tr><tr><td>渗透测试入门</td><td>networkLearning/38 ✅</td><td>互补,本系列偏方法论 + 工具链(21-25)</td></tr><tr><td>OAuth2 / OIDC / SSO</td><td>backendLearning/53 ✅</td><td>不重复,只讲 OAuth <strong>流程缺陷与攻击</strong>(15)</td></tr><tr><td>Web 认证基础</td><td>webLearning/35 ✅</td><td>不重复,只在 09-15 深入注入与会话攻击</td></tr><tr><td>容器底层</td><td>osLearning/25 ✅</td><td>不重复,本系列只讲容器 <strong>攻击面</strong>(28)</td></tr><tr><td>K8s 部署</td><td>backendLearning/27-30 ✅</td><td>不重复,只讲 K8s <strong>错配与提权</strong>(28)</td></tr><tr><td>LLM / Agent</td><td>aiLearning ✅ / claudeLearning ✅</td><td>不重复,只讲 LLM <strong>安全威胁</strong>(30)</td></tr></tbody></table><hr><h2 id="写作模板" tabindex="-1">写作模板 <a class="header-anchor" href="#写作模板" aria-label="Permalink to &quot;写作模板&quot;">​</a></h2><p>每篇遵守&quot;漏洞原因 → 利用链 → 实战示例 → 修复 → 防御深度&quot;的五段式:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 这个漏洞 / 风险为什么存在</span></span>
<span class="line"><span>   - 设计层面的根本缺陷</span></span>
<span class="line"><span>   - 历史背景(为什么以前没人发现)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 攻击者怎么利用它</span></span>
<span class="line"><span>   - 利用链 step by step</span></span>
<span class="line"><span>   - 真实 CVE 或者 CTF 题为例</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 一段最小可复现代码</span></span>
<span class="line"><span>   - 漏洞代码 + 攻击 payload</span></span>
<span class="line"><span>   - 不堆完整 exploit,只讲清楚关键一步</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 怎么修(短期补丁 + 长期重构)</span></span>
<span class="line"><span>   - 黑名单 vs 白名单</span></span>
<span class="line"><span>   - 框架级的彻底防御</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 纵深防御</span></span>
<span class="line"><span>   - 单点修复不够,加一道 WAF / CSP / 监控</span></span>
<span class="line"><span>   - 真实公司是怎么把它写进 SDL 的</span></span></code></pre></div><p>不堆 payload 字典,<strong>只贴关键的 5-10 行 PoC</strong>,让读者「看到漏洞是怎么一步步发生的」就够了。</p><hr><h2 id="节奏" tabindex="-1">节奏 <a class="header-anchor" href="#节奏" aria-label="Permalink to &quot;节奏&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01-03  心智:看完知道&quot;安全是一种工程纪律,不是事后打补丁&quot;</span></span>
<span class="line"><span>04-08  密码学:看完不会再&quot;自己加盐 MD5&quot;,也不会&quot;AES 直接 ECB&quot;</span></span>
<span class="line"><span>09-15  Web 安全:**最值钱的一层**,工程师 80% 的安全工作都在这</span></span>
<span class="line"><span>16-20  二进制:**最反直觉**,但理解了你才知道为什么 Rust / Go 火</span></span>
<span class="line"><span>21-25  渗透:看完知道&quot;攻击者拿到第一台机器之后,接下来 30 步是什么&quot;</span></span>
<span class="line"><span>26-30  工程:**面试和真实工作的硬通货**,SDL / 供应链 / AI 安全是当下热点</span></span></code></pre></div><p><strong>一个硬指标</strong>:看完 09-15 + 26-30 这 12 篇,你应该能在白板前讲清楚:</p><ul><li>&quot;为什么 prepared statement 不是万能的,模板注入怎么绕过 ORM&quot;</li><li>&quot;为什么 JWT 默认配置依然能被攻击,要禁用哪个算法&quot;</li><li>&quot;为什么 npm 安装一个包就能拿到你 token,SLSA 怎么解&quot;</li><li>&quot;如果你给一个 LLM Agent 接了文件系统工具,Prompt 注入能干掉什么&quot;</li></ul><p>能讲清楚一题这个系列就值了。</p><hr><h2 id="反对的写法" tabindex="-1">反对的写法 <a class="header-anchor" href="#反对的写法" aria-label="Permalink to &quot;反对的写法&quot;">​</a></h2><p>这个系列<strong>不写</strong>这些东西,见到了就是写错了:</p><ol><li>「下载这个工具,一把梭」——不是黑客教程,是工程师视角</li><li>「先讲个 APT 故事 / 黑客大佬传记」——直接进重点</li><li>罗列 CVE 编号——只在举例时引用关键 CVE</li><li>「这是面试常考」——读者来这里是为了真懂,不是背名词</li><li>完整 0day 利用代码 / 实战攻击手法——只到 PoC 层面,不教武器化</li><li>不画图就讲 OAuth 流程 / ROP 链 / TLS 握手——这些东西<strong>不画图永远讲不清楚</strong></li><li>抄 OWASP Cheat Sheet——那个文档在那儿,这里只补它没讲透的&quot;为什么&quot;</li></ol><hr><h2 id="立场声明" tabindex="-1">立场声明 <a class="header-anchor" href="#立场声明" aria-label="Permalink to &quot;立场声明&quot;">​</a></h2><p>本系列<strong>只服务于防御方视角</strong>——理解攻击是为了写出更安全的代码、做更准的代码评审、设计更可靠的系统。</p><p>所有示例代码限制在最小可复现 PoC,<strong>不提供任何用于未授权访问的完整利用工具或自动化武器</strong>。CTF / 渗透篇章默认目标是<strong>自己搭的靶机或授权环境</strong>。</p>`,44)])])}const g=n(l,[["render",i]]);export{c as __pageData,g as default};
